import React, { useState, useEffect } from 'react';
import { View, Text, Button, Alert, TextInput } from 'react-native';
import * as Biometric from 'react-native-biometrics';

const App = () => {
  const [biometryType, setBiometryType] = useState('');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [fallbackPassword, setFallbackPassword] = useState('');

  useEffect(() => {
    checkBiometricSupport();
  }, []);

  const checkBiometricSupport = async () => {
    try {
      const result = await Biometric.isEnrolled();
      if (result === 'FaceID') {
        setBiometryType('faceid');
      } else if (result === 'TouchID' || result === 'Fingerprint') {
        setBiometryType('fingerprint');
      }
    } catch (error) {
      console.error(error);
    }
  };

  const authenticate = async () => {
    try {
      if (biometryType === '') return;
      if (isAuthenticated) return;

      Alert.alert(
        'Authentication Required',
        `Please verify your ${biometryType} to proceed.`,
        [
          {
            text: 'Cancel',
            style: 'cancel',
          },
          {
            text: 'Verify',
            onPress: async () => {
              try {
                const result = await Biometric.verify({ promptMessage: 'Enter password for fallback' });
                if (result) {
                  setIsAuthenticated(true);
                } else {
                  Alert.alert('Authentication Failed', 'Please try again.');
                }
              } catch (error) {
                console.error(error);
              }
            },
          },
        ],
      );
    } catch (error) {
      console.error(error);
    }
  };

  const login = async () => {
    if (isAuthenticated) return;
    Alert.alert(
      'Login Required',
      'Please enter your password to proceed.',
      [
        {
          text: 'Cancel',
          style: 'cancel',
        },
        {
          text: 'Submit',
          onPress: async () => {
            try {
              const result = await Biometric.verify({ promptMessage: 'Enter password' });
              if (result) {
                setIsAuthenticated(true);
              } else {
                Alert.alert('Authentication Failed', 'Please try again.');
              }
            } catch (error) {
              console.error(error);
            }
          },
        },
      ],
    );
  };

  const saveAuthenticatedFlag = async () => {
    await AsyncStorage.setItem('is_authenticated', 'true');
  };

  return (
    <View>
      <Text>Biometric Authentication Example</Text>

      {isAuthenticated && <Text>Logged In!</Text>}
      {!isAuthenticated && (
        <>
          <Button title="Authenticate" onPress={authenticate} />
          <Button title="Login" onPress={login} />
        </>
      )}

      <TextInput
        placeholder="Fallback Password"
        secureTextEntry={true}
        value={fallbackPassword}
        onChangeText={(text) => setFallbackPassword(text)}
      />

      <Button title="Save Authenticated Flag" onPress={saveAuthenticatedFlag} />
    </View>
  );
};

export default App;